import React from 'react';
import { AnimatePresence, motion, useReducedMotion } from 'framer-motion';

type LabeledSliderProps = {
  label: string;
  value: number;
  min: number;
  max: number;
  step?: number;
  onChange: (value: number) => void;
  formatValue: (value: number) => string;
};

const LabeledSlider: React.FC<LabeledSliderProps> = ({
  label,
  value,
  min,
  max,
  step = 1,
  onChange,
  formatValue,
}) => {
  const reduceMotion = useReducedMotion();
  const progress = ((value - min) / (max - min)) * 100;

  return (
    <div className="space-y-6">
      <div className="flex items-end justify-between gap-4">
        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-muted/95">{label}</p>

        <div className="relative min-w-[100px] text-right">
          <AnimatePresence mode="popLayout" initial={false}>
            <motion.span
              key={value}
              initial={reduceMotion ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.94 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={reduceMotion ? { opacity: 1 } : { opacity: 0, scale: 0.96 }}
              transition={{ duration: reduceMotion ? 0.12 : 0.18, ease: 'easeOut' }}
              className="inline-flex rounded-full border border-stroke bg-white/[0.07] px-4 py-1.5 text-[0.95rem] font-black tracking-wide text-gold"
            >
              {formatValue(value)}
            </motion.span>
          </AnimatePresence>
        </div>
      </div>

      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(event) => onChange(Number(event.target.value))}
        style={{
          background: `linear-gradient(90deg, rgba(16,185,129,0.95) 0%, rgba(16,185,129,0.7) ${progress}%, rgba(148,163,184,0.2) ${progress}%, rgba(148,163,184,0.2) 100%)`,
          boxShadow: 'inset 0 0 10px rgba(16,185,129,0.22)',
        }}
        className="h-2.5 w-full cursor-pointer appearance-none rounded-full shadow-inner
          [&::-webkit-slider-runnable-track]:h-2.5 [&::-webkit-slider-runnable-track]:rounded-full [&::-webkit-slider-runnable-track]:bg-transparent
          [&::-webkit-slider-thumb]:-mt-[7px] [&::-webkit-slider-thumb]:h-6 [&::-webkit-slider-thumb]:w-6 [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:border [&::-webkit-slider-thumb]:border-white/70 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-[0_0_0_4px_rgba(16,185,129,0.22),0_0_18px_rgba(16,185,129,0.6)]
          [&::-moz-range-track]:h-2.5 [&::-moz-range-track]:rounded-full [&::-moz-range-track]:bg-transparent
          [&::-moz-range-thumb]:h-6 [&::-moz-range-thumb]:w-6 [&::-moz-range-thumb]:rounded-full [&::-moz-range-thumb]:border [&::-moz-range-thumb]:border-white/70 [&::-moz-range-thumb]:bg-white [&::-moz-range-thumb]:shadow-[0_0_0_4px_rgba(16,185,129,0.22),0_0_18px_rgba(16,185,129,0.6)]
          focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/70"
      />
    </div>
  );
};

export default LabeledSlider;
